// Busca dados com tratamento de erro
let mainCoins = [];
let top20 = [];
let fearGreed = { data: [{ value: 'N/A', value_classification: 'N/A' }] };
let rssCT = [];
let rssCD = [];
let rssDecrypt = [];
let rssInvesting = [];

try { mainCoins = $('CoinGecko - BTC ETH SOL').all().map(i => i.json); } catch(e) {}
try { top20 = $('CoinGecko - Top 20 por Volume').all().map(i => i.json); } catch(e) {}
try { fearGreed = $('Fear and Greed Index').first().json; } catch(e) {}
try { rssCT = $('RSS - CoinTelegraph').all().map(i => i.json); } catch(e) {}
try { rssCD = $('RSS - CoinDesk').all().map(i => i.json); } catch(e) {}
try { rssDecrypt = $('RSS - Decrypt').all().map(i => i.json); } catch(e) {}
try { rssInvesting = $('RSS - Investing').all().map(i => i.json); } catch(e) {}

// Junta todas as notícias e pega as 10 mais recentes
const allNews = [...rssCT, ...rssCD, ...rssDecrypt, ...rssInvesting]
  .sort((a, b) => new Date(b.pubDate || b.isoDate) - new Date(a.pubDate || a.isoDate))
  .slice(0, 11)
  .map(n => ({ title: n.title, summary: n.contentSnippet || n.summary || '', source: n.link, date: n.pubDate || n.isoDate }));

// Filtra altcoins excluindo BTC/ETH/SOL
const altcoins = top20
  .filter(c => !['bitcoin','ethereum','solana'].includes(c.id))
  .slice(0, 5)
  .map(c => ({
    name: c.name,
    symbol: c.symbol.toUpperCase(),
    price: c.current_price,
    change24h: c.price_change_percentage_24h?.toFixed(2),
    change7d: c.price_change_percentage_7d_in_currency?.toFixed(2),
    marketCap: c.market_cap,
    volume24h: c.total_volume
  }));

// Formata principais moedas
const mainFormatted = mainCoins.map(c => ({
  name: c.name,
  symbol: c.symbol.toUpperCase(),
  price: c.current_price,
  change24h: c.price_change_percentage_24h?.toFixed(2),
  change7d: c.price_change_percentage_7d_in_currency?.toFixed(2),
  marketCap: c.market_cap,
  volume24h: c.total_volume,
  high24h: c.high_24h,
  low24h: c.low_24h
}));

const fgData = fearGreed.data?.[0];

return [{
  json: {
    mainCoins: mainFormatted,
    altcoins,
    fearGreed: {
      value: fgData?.value,
      classification: fgData?.value_classification
    },
    news: allNews,
    generatedAt: new Date().toISOString()
  }
}];

const groqResponse = $input.first().json;
const analysisText = groqResponse.choices?.[0]?.message?.content || 'Erro ao gerar análise.';

const now = new Date();
const dateStr = now.toLocaleDateString('pt-BR', { 
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' 
});

const cleanText = analysisText
  .replace(/#{1,6}\s/g, '')
  .replace(/\*\*(.*?)\*\*/g, '*$1*')
  .replace(/__(.*?)__/g, '_$1_')
  .replace(/\n{3,}/g, '\n\n');

const header = `📊 *CRYPTO MORNING REPORT*\n_${dateStr}_\n\n`;
const footer = `\n\n─────────────────────\n_Não é recomendação de investimento_`;
const fullMessage = header + cleanText + footer;

// Divide em 3 partes nos separadores ━━━
const sections = fullMessage.split('━━━━━━━━━━━━━━━━━━━━━━');

const part1 = sections.slice(0, 3).join('━━━━━━━━━━━━━━━━━━━━━━');
const part2 = sections.slice(3, 5).join('━━━━━━━━━━━━━━━━━━━━━━');
const part3 = (sections.slice(5).join('━━━━━━━━━━━━━━━━━━━━━━') || '') + footer;

return [
  { json: { message: part1 } },
  { json: { message: part2 } },
  { json: { message: part3 } }
];
